1	export function scalePixelArt(image: string[], scale: number): string[] {
2	  return image.flatMap((row) => {
3	    const horizontallyScaledRow = row.repeat(scale);
4	    return Array(scale).fill(horizontallyScaledRow);
5	  });
6	}
